  7	import { GrayUnknownIcon } from '@odf/shared/status/icons';
  8	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  9	import { referenceForModel } from '@odf/shared/utils';
 10	import {
 11	  StatusIconAndText,
 12	  useK8sWatchResource,
 13	  HealthState,
 14	} from '@openshift-console/dynamic-plugin-sdk';
 15	import * as _ from 'lodash-es';
 16	import { TFunction } from 'react-i18next';
 17	import { Trans } from 'react-i18next';
 18	import { ChartPie, ChartThemeColor } from '@patternfly/react-charts/victory';
 19	import {
 20	  ExpandableSection,
 21	  Popover,
 22	  PopoverPosition,
 23	  Button,
 24	  List,
 25	  ListItem,
 26	  Card,
 27	  CardBody,
 28	  CardHeader,
 29	  CardTitle,
