 33	  CephBlockPoolRadosNamespaceKind,
 34	  States,
 35	  StoragePoolKind,
 36	} from '../../types';
 37	import { twelveHoursdateTimeNoYear } from '../../utils';
 38	import { calcPercentage } from '../../utils/common';
 39	import { BlockPoolDashboardContext } from './block-pool-dashboard-context';
 40	import { MirroringCardBody } from './mirroring-card-body';
 41	import { MirroringCardItem } from './mirroring-card-item';
 42	import { getColor } from './states';
 43	import { ImageStateLegendMap, healthStateMessage } from './states';
 44	import './mirroring-card.scss';
 45	
 46	const defaultState = {
 47	  priority: -1,
 48	  health: HealthState.UNKNOWN,
 49	  icon: <GrayUnknownIcon title="Unknown" />,
 50	};
 51	
 52	const aggregateHealth = (
 53	  poolObj: StoragePoolKind,
 54	  radosNamespaces: CephBlockPoolRadosNamespaceKind[]
 55	): HealthStateMappingValues[] => {
 56	  let mirroringHealth: HealthStateMappingValues =
 57	    healthStateMapping[poolObj.status?.mirroringStatus?.summary?.health] ||
 58	    defaultState;
 59	  let imageHealth: HealthStateMappingValues =
 60	    healthStateMapping[
 61	      poolObj.status?.mirroringStatus?.summary?.image_health
 62	    ] || defaultState;
 63	  radosNamespaces.forEach((radosNamespace) => {
 64	    // Mirroring health
 65	    const radosNamespaceMirroringHealth: HealthStateMappingValues =
 66	      healthStateMapping[
 67	        radosNamespace.status?.mirroringStatus?.summary?.health
 68	      ] || defaultState;
 69	    if (!!radosNamespaceMirroringHealth) {
 70	      mirroringHealth =
 71	        mirroringHealth.priority > radosNamespaceMirroringHealth.priority
 72	          ? mirroringHealth
 73	          : radosNamespaceMirroringHealth;
 74	    }
 75	
 76	    // Image health
 77	    const radosNamespaceImageHealth: HealthStateMappingValues =
 78	      healthStateMapping[
 79	        radosNamespace.status?.mirroringStatus?.summary?.image_health
 80	      ] || defaultState;
 81	    if (!!radosNamespaceImageHealth) {
 82	      imageHealth =
 83	        imageHealth.priority > radosNamespaceImageHealth.priority
 84	          ? imageHealth
 85	          : radosNamespaceImageHealth;
 86	    }
 87	  });
 88	  return [mirroringHealth, imageHealth];
 89	};
 90	
 91	const aggregateMirroringStatusCheckedTime = (
 92	  poolObj: StoragePoolKind,
 93	  radosNamespaces: CephBlockPoolRadosNamespaceKind[]
 94	): string => {
 95	  let lastChecked: string = poolObj.status?.mirroringStatus?.lastChecked;
 96	  radosNamespaces.forEach((radosNamespace) => {
 97	    const radosNamespaceLastChecked: string =
 98	      radosNamespace.status?.mirroringStatus?.lastChecked;
 99	    if (!!radosNamespaceLastChecked) {
100	      lastChecked = getLatestDate([lastChecked, radosNamespaceLastChecked]);
101	    }
102	  });
103	  return lastChecked;
104	};
105	
106	const aggregateMirroringStates = (
107	  poolObj: StoragePoolKind,
108	  radosNamespaces: CephBlockPoolRadosNamespaceKind[]
109	): States => {
110	  const states: States =
111	    _.cloneDeep(poolObj.status?.mirroringStatus?.summary?.states) ?? {};
112	  radosNamespaces.forEach((radosNamespace) => {
113	    const radosNamespaceStates: States =
114	      radosNamespace.status?.mirroringStatus?.summary?.states ?? {};
115	    if (!!radosNamespaceStates) {
116	      Object.entries(radosNamespaceStates).forEach(([state, count]) => {
117	        const oldCount = states?.[state] || 0;
118	        states[state] = oldCount + count;
119	      });
120	    }
121	  });
122	  return states;
123	};
124	
125	const getPieChartHeight = (numOfStates: number) => {
126	  if (numOfStates <= 3) {
127	    return 150;
128	  } else if (numOfStates <= 5) {
129	    return 200;
130	  }
131	  return 240;
132	};
133	
134	const MirroringImageStatePopover: React.FC<MirroringImageStatePopoverProps> = ({
135	  t,
136	}) => {
137	  return (
138	    <Popover
139	      maxWidth="32rem"
140	      position={PopoverPosition.left}
141	      aria-label={t('Image states info')}
142	      bodyContent={
143	        <List isPlain>
144	          <ListItem>
145	            <strong> {t('What does each state mean?')}</strong>
146	          </ListItem>
147	          <ListItem>
148	            <Trans t={t} ns="plugin__odf-console">
149	              <strong>Starting replay:</strong> Initiating image (PV)
150	              replication process.
151	            </Trans>
152	          </ListItem>
153	          <ListItem>
154	            <Trans t={t} ns="plugin__odf-console">
155	              <strong>Replaying:</strong> Image (PV) replication is ongoing or
156	              idle between clusters.
157	            </Trans>
158	          </ListItem>
159	          <ListItem>
160	            <Trans t={t} ns="plugin__odf-console">
161	              <strong>Stopping replay:</strong> Image (PV) replication process
162	              is shutting down.
163	            </Trans>
164	          </ListItem>
165	          <ListItem>
166	            <Trans t={t} ns="plugin__odf-console">
167	              <strong>Stopped:</strong> Image (PV) replication process has shut
168	              down.
169	            </Trans>
170	          </ListItem>
171	          <ListItem>
172	            <Trans t={t} ns="plugin__odf-console">
173	              <strong>Error:</strong> Image (PV) replication process stopped due
174	              to an error.
175	            </Trans>
176	          </ListItem>
177	          <ListItem>
178	            <Trans t={t} ns="plugin__odf-console">
179	              <strong>Unknown:</strong> Unable to determine image (PV) state due
180	              to an error. Check your network connection and remote cluster
181	              mirroring daemon.
182	            </Trans>
183	          </ListItem>
184	        </List>
185	      }
186	    >
187	      <Button
188	        aria-label={t('image states info')}
189	        variant="link"
190	        isInline
191	        className="odf-block-pool-mirroring-help"
192	      >
193	        <OutlinedQuestionCircleIcon className="odf-block-pool-mirroring-help__icon" />
194	        What does each state mean?
195	      </Button>
196	    </Popover>
197	  );
198	};
199	
200	const MirroringImageHealthChart: React.FC<MirroringImageHealthChartProps> = ({
201	  t,
202	  states,
203	}) => {
204	  const totalImageCount = Object.keys(states).reduce(
205	    (sum, state) => sum + states[state],
206	    0
207	  );
208	
209	  if (totalImageCount > 0) {
210	    const { data, legendData, colorScale } = Object.keys(states).reduce(
211	      (acc, state) => {
212	        const percentage = calcPercentage(states[state], totalImageCount);
213	        const status = ImageStateLegendMap(t)[state];
214	        acc.data.push({
215	          x: status,
216	          y: percentage.value,
217	        });
218	        acc.legendData.push({
219	          name: `${status}: ${percentage.string}`,
220	          symbol: { fill: getColor(state) },
221	        });
222	        acc.colorScale.push(getColor(state));
223	        return acc;
224	      },
225	      { data: [], legendData: [], colorScale: [] }
226	    );
227	
228	    return (
229	      <div style={{ maxHeight: '240px', maxWidth: '300px' }}>
230	        <ChartPie
231	          ariaTitle={t('Image States')}
232	          colorScale={colorScale}
233	          constrainToVisibleArea
234	          data={data}
235	          labels={({ datum }) => `${datum.x}: ${datum.y}`}
236	          legendData={legendData}
237	          legendOrientation="vertical"
238	          legendPosition="right"
239	          height={getPieChartHeight(data.length)}
240	          width={300}
241	          padding={{
242	            right: 190,
243	          }}
244	          themeColor={ChartThemeColor.multi}
245	        />
246	      </div>
247	    );
248	  }
249	  return null;
250	};
251	
252	export const MirroringCard: React.FC = () => {
253	  const { t } = useCustomTranslation();
254	  const { obj } = React.useContext(BlockPoolDashboardContext);
255	  // watch all cephradosnamespace
256	  const [radosNamespaces, isLoaded, isLoadError] = useK8sWatchResource<
257	    CephBlockPoolRadosNamespaceKind[]
258	  >({
259	    isList: true,
260	    kind: referenceForModel(CephBlockPoolRadosNamespaceModel),
261	    namespace: getNamespace(obj),
262	    selector: {
263	      matchLabels: {
264	        [BLOCK_POOL_NAME_LABEL]: getName(obj),
265	      },
266	    },
267	  });
268	
269	  const mirroringStatus: boolean = obj.spec?.mirroring?.enabled;
270	  const [mirroringHealth, imageHealth]: HealthStateMappingValues[] =
271	    aggregateHealth(obj, radosNamespaces);
272	  const lastChecked: string = aggregateMirroringStatusCheckedTime(
273	    obj,
274	    radosNamespaces
275	  );
276	  const states: States = aggregateMirroringStates(obj, radosNamespaces);
277	  const formatedDateTime = !!lastChecked
278	    ? twelveHoursdateTimeNoYear.format(new Date(lastChecked))
279	    : '-';
280	
281	  return (
282	    <Card data-test-id="mirroring-card">
283	      <CardHeader>
284	        <CardTitle>{t('Mirroring')}</CardTitle>
285	      </CardHeader>
286	      <CardBody>
287	        <MirroringCardBody>
288	          <MirroringCardItem
289	            isLoading={!isLoaded}
290	            error={!!isLoadError}
291	            title={t('Mirroring status')}
292	          >
293	            {mirroringStatus ? t('Enabled') : t('Disabled')}
294	          </MirroringCardItem>
295	          {mirroringStatus && (
296	            <>
297	              <MirroringCardItem
298	                isLoading={!isLoaded}
299	                error={!!isLoadError}
300	                title={t('Mirroring health')}
301	              >
302	                <StatusIconAndText
303	                  title={healthStateMessage(mirroringHealth?.health, t)}
304	                  icon={mirroringHealth?.icon as React.ReactElement}
305	                  className="pf-v6-u-ml-xs"
306	                />
307	              </MirroringCardItem>
308	              <MirroringCardItem
309	                isLoading={!isLoaded}
310	                error={!!isLoadError}
311	                title={t('Overall image health')}
312	              >
313	                <StatusIconAndText
314	                  title={healthStateMessage(imageHealth?.health, t)}
315	                  icon={imageHealth?.icon as React.ReactElement}
316	                  className="pf-v6-u-ml-xs"
317	                />
318	              </MirroringCardItem>
319	              {!_.isEmpty(states) && (
320	                <>
321	                  <MirroringCardItem
322	                    isLoading={!isLoaded}
323	                    error={!!isLoadError}
324	                  >
325	                    <ExpandableSection toggleText={t('Show image states')}>
326	                      <MirroringImageHealthChart t={t} states={states} />
327	                    </ExpandableSection>
328	                  </MirroringCardItem>
329	                  <MirroringCardItem
330	                    isLoading={!isLoaded}
331	                    error={!!isLoadError}
332	                  >
333	                    <MirroringImageStatePopover t={t} />
334	                  </MirroringCardItem>
335	                </>
336	              )}
337	              <MirroringCardItem
338	                isLoading={!isLoaded}
339	                error={!!isLoadError}
340	                title={t('Last checked')}
341	              >
342	                {formatedDateTime}
343	              </MirroringCardItem>
344	            </>
345	          )}
346	        </MirroringCardBody>
347	      </CardBody>
348	    </Card>
349	  );
350	};
351	
352	type MirroringImageStatePopoverProps = {
353	  t: TFunction;
354	};
355	
356	type MirroringImageHealthChartProps = {
357	  t: TFunction;
358	  states: States;
359	};

