 50	};
 51	
 52	const aggregateHealth = (
 53	  poolObj: StoragePoolKind,
 54	  radosNamespaces: CephBlockPoolRadosNamespaceKind[]
 55	): HealthStateMappingValues[] => {
 56	  let mirroringHealth: HealthStateMappingValues =
 57	    healthStateMapping[poolObj.status?.mirroringStatus?.summary?.health] ||
