 91	const aggregateMirroringStatusCheckedTime = (
 92	  poolObj: StoragePoolKind,
 93	  radosNamespaces: CephBlockPoolRadosNamespaceKind[]
 94	): string => {
 95	  let lastChecked: string = poolObj.status?.mirroringStatus?.lastChecked;
 96	  radosNamespaces.forEach((radosNamespace) => {
 97	    const radosNamespaceLastChecked: string =
 98	      radosNamespace.status?.mirroringStatus?.lastChecked;
 99	    if (!!radosNamespaceLastChecked) {
100	      lastChecked = getLatestDate([lastChecked, radosNamespaceLastChecked]);
101	    }
102	  });
103	  return lastChecked;
104	};
